package com.practice.core.service;

import com.fasterxml.jackson.databind.*;import com.practice.core.entity.*;import com.practice.core.dao.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.*;import org.springframework.transaction.support.*;import java.net.URI;import java.net.http.*;import java.nio.charset.StandardCharsets;import java.nio.file.*;import java.time.*;import java.util.*;import java.util.regex.*;import java.util.stream.*;

@Service
public class PlatformCoreService {
    final DeviceDao devices; final ProductDao products; final DeviceGroupDao groups; final TelemetryDao telemetry; final RuleDao rules; final AlarmDao alarms; final RuleAuditDao audits; final TaskJobDao tasks; final TaskLogDao taskLogs; final OperationLogDao opLogs; final UserDao users; final LoginLogDao loginLogs; final AiAgentDao aiAgents; final RealtimeEventService realtimeEvents;
    final ObjectMapper mapper = new ObjectMapper();
    @Value("${app.ai.enabled:true}") boolean aiEnabled; @Value("${app.ai.base-url:https://maas.icompify.com:32788/v1}") String aiBaseUrl; @Value("${app.ai.model:deepseek-v4-flash}") String aiModel; @Value("${app.ai.api-key:}") String aiApiKey; @Value("${app.ai.timeout-ms:25000}") long aiTimeoutMs; @Value("${app.ai.allow-local-key-file:false}") boolean aiAllowLocalKeyFile;
    public PlatformCoreService(DeviceDao devices, ProductDao products, DeviceGroupDao groups, TelemetryDao telemetry, RuleDao rules, AlarmDao alarms, RuleAuditDao audits, TaskJobDao tasks, TaskLogDao taskLogs, OperationLogDao opLogs, UserDao users, LoginLogDao loginLogs, AiAgentDao aiAgents, RealtimeEventService realtimeEvents){this.devices=devices;this.products=products;this.groups=groups;this.telemetry=telemetry;this.rules=rules;this.alarms=alarms;this.audits=audits;this.tasks=tasks;this.taskLogs=taskLogs;this.opLogs=opLogs;this.users=users;this.loginLogs=loginLogs;this.aiAgents=aiAgents;this.realtimeEvents=realtimeEvents;}
    @Transactional public Map<String,Object> login(String username,String password,String token,String ip){SysUser u=users.findByUsername(username);boolean ok=u!=null&&Objects.equals(u.password,password);LoginLog log=new LoginLog();log.name="登录-"+username;log.username=username;log.ip=ip;log.success=ok;loginLogs.save(log);if(!ok)throw new RuntimeException("用户名或密码错误");op("系统设置","登录",username,"用户登录成功");Map<String,Object> user=new LinkedHashMap<>();user.put("id",u.id);user.put("username",u.username);user.put("name",u.name);user.put("realName",u.realName==null?username:u.realName);user.put("role",u.roleName==null||u.roleName.isBlank()?"":u.roleName);user.put("roleName",u.roleName==null||u.roleName.isBlank()?"":u.roleName);user.put("status",u.status);user.put("createdAt",u.createdAt);user.put("updatedAt",u.updatedAt);Map<String,Object> result=new LinkedHashMap<>();result.put("token",token);result.put("tokenType","Bearer");result.put("username",username);result.put("realName",user.get("realName"));result.put("role",user.get("role"));result.put("roleName",user.get("roleName"));result.put("user",user);return result;}
    @Transactional public Map<String,Object> simulate(Map<String,Object> req){return processTelemetry(req,"数据中心","模拟上报","admin");}
    @Transactional public Map<String,Object> report(Map<String,Object> req){String operator=str(req.get("deviceKey"));if(operator.isBlank())operator=str(req.get("deviceCode"));if(operator.isBlank())operator="device";return processTelemetry(req,"设备接入","设备上报",operator);}
    Map<String,Object> processTelemetry(Map<String,Object> req,String module,String action,String operator){Device device=resolveDevice(req);TelemetryData data=new TelemetryData();data.deviceId=device.id;data.deviceName=device.name;data.temperature=num(req.get("temperature"));data.humidity=num(req.get("humidity"));data.pressure=num(req.get("pressure"));data.payload=payload(req);telemetry.save(data);device.status="ONLINE";device.lastOnlineAt=LocalDateTime.now();devices.save(device);List<Alarm> created=new ArrayList<>();for(Rule rule:rules.findByEnabledTrue()){Double value=metricValue(rule.metric,req,data);boolean hit=value!=null&&compare(value,rule.operator,rule.threshold);RuleAudit audit=new RuleAudit();audit.name="规则审计-"+rule.name;audit.ruleId=rule.id;audit.deviceId=device.id;audit.status=hit?"HIT":"PASS";audit.result=audit.status;String ruleAction=str(rule.action).isBlank()?"生成告警":str(rule.action);audit.detail=rule.metric+"="+value+" "+rule.operator+" "+rule.threshold+"，动作："+ruleAction;audits.save(audit);if(hit&&!"仅记录规则审计".equals(ruleAction)){Alarm alarm=new Alarm();alarm.name="阈值告警-"+device.name;alarm.code="ALM-"+System.currentTimeMillis();alarm.status="OPEN";alarm.deviceId=device.id;alarm.deviceName=device.name;alarm.ruleId=rule.id;alarm.level=rule.alarmLevel;alarm.type="THRESHOLD";alarm.ruleName=rule.name;alarm.content=audit.detail+"，触发规则："+rule.name;alarms.save(alarm);created.add(alarm);}}op(module,action,operator,"设备"+device.name+"上报遥测数据");broadcastTelemetryEvent(device,data,created);return Map.of("telemetry",data,"alarms",created);}
    Device resolveDevice(Map<String,Object> req){String deviceKey=str(req.get("deviceKey"));if(!deviceKey.isBlank()){Device device=devices.findByDeviceKey(deviceKey);if(device!=null)return device;}String deviceCode=str(req.get("deviceCode"));if(!deviceCode.isBlank()){Device device=devices.findByCode(deviceCode);if(device!=null)return device;}String deviceId=str(req.get("deviceId"));if(!deviceId.isBlank())return devices.findById(Long.valueOf(deviceId)).orElseThrow(()->new RuntimeException("设备不存在"));throw new RuntimeException("设备不存在，请提供 deviceId、deviceKey 或 deviceCode");}
    String payload(Map<String,Object> req){try{return mapper.writeValueAsString(req);}catch(Exception ignored){return String.valueOf(req);}}
    void broadcastTelemetryEvent(Device device,TelemetryData data,List<Alarm> created){Map<String,Object> event=Map.of("deviceId",device.id,"deviceName",device.name,"telemetryId",data.id,"alarmCount",created.size(),"hasAlarm",!created.isEmpty(),"hasHighAlarm",created.stream().anyMatch(a->"HIGH".equals(a.level)||"高".equals(a.level)));if(TransactionSynchronizationManager.isSynchronizationActive())TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization(){@Override public void afterCommit(){realtimeEvents.broadcast("telemetry",event);}});else realtimeEvents.broadcast("telemetry",event);}
    public Map<String,Object> summary(){return Map.of("products",products.count(),"groups",groups.count(),"devices",devices.count(),"onlineDevices",devices.countByStatus("ONLINE"),"alarms",alarms.count(),"openAlarms",alarms.countByStatus("OPEN"),"telemetryToday",telemetry.countByReportTimeAfter(LocalDate.now().atStartOfDay()),"tasks",tasks.count());}
    public Map<String,Object> charts(){List<Device> ds=devices.findAll();Map<String,Long> byStatus=ds.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.status).orElse("UNKNOWN"),Collectors.counting()));List<Alarm> as=alarms.findAll();Map<String,Long> byLevel=as.stream().collect(Collectors.groupingBy(x->Optional.ofNullable(x.level).orElse("INFO"),Collectors.counting()));List<LocalDate> dayDates=IntStream.rangeClosed(0,6).mapToObj(i->LocalDate.now().minusDays(6-i)).toList();List<String> days=dayDates.stream().map(LocalDate::toString).toList();LocalDateTime windowStart=dayDates.get(0).atStartOfDay().minusNanos(1);Map<LocalDate,Long> messageCounts=telemetry.findByReportTimeAfter(windowStart).stream().filter(x->x.reportTime!=null).collect(Collectors.groupingBy(x->x.reportTime.toLocalDate(),Collectors.counting()));Map<LocalDate,Long> deviceCounts=devices.findByCreatedAtAfter(windowStart).stream().filter(x->x.createdAt!=null).collect(Collectors.groupingBy(x->x.createdAt.toLocalDate(),Collectors.counting()));Map<LocalDate,Long> alarmCounts=alarms.findByCreatedAtAfter(windowStart).stream().filter(x->x.createdAt!=null).collect(Collectors.groupingBy(x->x.createdAt.toLocalDate(),Collectors.counting()));return Map.of("deviceStatus",byStatus,"alarmLevel",byLevel,"days",days,"messageTrend",trend(dayDates,messageCounts),"deviceGrowth",trend(dayDates,deviceCounts),"alarmTrend",trend(dayDates,alarmCounts),"recentTelemetry",telemetry.findTop50ByOrderByReportTimeDesc(),"recentAlarms",alarms.findTop20ByOrderByCreatedAtDesc());}
    public List<TelemetryData> recentTelemetry(){return telemetry.findTop50ByOrderByReportTimeDesc();} public List<TaskLog> taskLogs(){return taskLogs.findTop50ByOrderByExecuteTimeDesc();}
    @Transactional public Alarm handleAlarm(Long id,Map<String,Object> body){Alarm a=alarms.findById(id).orElseThrow();a.status="CLOSED";a.handler=String.valueOf(body.getOrDefault("handler","admin"));a.remark=String.valueOf(body.getOrDefault("remark","已处置"));a.handledAt=LocalDateTime.now();op("规则引擎","处置告警",a.handler,a.name);return alarms.save(a);} @Transactional public TaskJob switchTask(Long id,boolean running){TaskJob t=tasks.findById(id).orElseThrow();t.running=running;t.status=running?"RUNNING":"STOPPED";t.lastResult=running?"任务已启动，等待调度":"任务已停止";tasks.save(t);TaskLog l=new TaskLog();l.name="任务日志-"+t.name;l.taskId=id;l.status="SUCCESS";l.result=t.lastResult;l.detail="模拟执行策略："+t.cron;taskLogs.save(l);return t;} @Transactional public void op(String module,String action,String operator,String detail){OperationLog l=new OperationLog();l.name=module+"-"+action;l.moduleName=module;l.action=action;l.operator=operator;l.detail=detail;opLogs.save(l);}
    public Map<String,Object> aiChat(Map<String,Object> req){String agentCode=str(req.get("agentCode"));String message=str(req.get("message"));String context=str(req.get("context"));AiAgent agent=agentCode.isBlank()?null:aiAgents.findByCode(agentCode);String requestedModel=str(req.get("model"));String model=!requestedModel.isBlank()?requestedModel:(agent!=null&&agent.modelName!=null&&!agent.modelName.isBlank()?agent.modelName:aiModel);if(model==null||model.isBlank())model="deepseek-v4-flash";if(agent!=null&&(Boolean.FALSE.equals(agent.enabled)||"DISABLED".equals(agent.status)))return demoAi(agent,message,model,"该智能体暂未启用，已切换为本地演示建议");if(!aiEnabled)return demoAi(agent,message,model,"智能服务暂未启用，已切换为本地演示建议");String key=resolveAiKey(req);if(key.isBlank())return demoAi(agent,message,model,"智能服务配置待完善，已切换为本地演示建议");try{String base=Optional.ofNullable(str(req.get("baseUrl")).isBlank()?aiBaseUrl:str(req.get("baseUrl"))).orElse("https://maas.icompify.com:32788/v1").replaceAll("/+$","");String system=agent!=null&&agent.systemPrompt!=null&&!agent.systemPrompt.isBlank()?agent.systemPrompt:"你是工业互联网平台的智能助手，请用中文给出简洁、可执行的建议。";List<Map<String,String>> messages=new ArrayList<>();messages.add(Map.of("role","system","content",system));if(!context.isBlank())messages.add(Map.of("role","user","content","业务上下文："+context));messages.add(Map.of("role","user","content",message.isBlank()?"请结合工业物联网场景给出建议":message));Map<String,Object> payload=new LinkedHashMap<>();payload.put("model",model);payload.put("messages",messages);payload.put("stream",false);payload.put("max_tokens",500);payload.put("temperature",0.3);HttpClient client=HttpClient.newBuilder().connectTimeout(Duration.ofMillis(aiTimeoutMs)).build();HttpRequest request=HttpRequest.newBuilder(URI.create(base+"/chat/completions")).timeout(Duration.ofMillis(aiTimeoutMs)).header("Authorization","Bearer "+key).header("Content-Type","application/json").POST(HttpRequest.BodyPublishers.ofString(mapper.writeValueAsString(payload),StandardCharsets.UTF_8)).build();HttpResponse<String> response=client.send(request,HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));if(response.statusCode()<200||response.statusCode()>=300)return demoAi(agent,message,model,"智能服务响应较慢，已切换为本地演示建议");JsonNode content=mapper.readTree(response.body()).path("choices").path(0).path("message").path("content");String reply=content.asText("").trim();if(reply.isBlank())return demoAi(agent,message,model,"智能服务响应较慢，已切换为本地演示建议");return Map.of("reply",reply,"source","LIVE","model",model,"notice","智能服务已生成建议");}catch(Exception ignored){return demoAi(agent,message,model,"智能服务响应较慢，已切换为本地演示建议");}}
    public Map<String,Object> aiModels(Map<String,Object> req){String key=resolveAiKey(req);String base=Optional.ofNullable(str(req.get("baseUrl")).isBlank()?aiBaseUrl:str(req.get("baseUrl"))).orElse("https://maas.icompify.com:32788/v1").replaceAll("/+$","");if(!aiEnabled)return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","智能服务暂未启用，当前显示默认模型");if(key.isBlank())return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","请填写 API Key，或使用本机示例配置");try{HttpClient client=HttpClient.newBuilder().connectTimeout(Duration.ofMillis(Math.min(aiTimeoutMs,10000))).build();HttpRequest request=HttpRequest.newBuilder(URI.create(base+"/models")).timeout(Duration.ofMillis(Math.min(aiTimeoutMs,15000))).header("Authorization","Bearer "+key).GET().build();HttpResponse<String> response=client.send(request,HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));if(response.statusCode()<200||response.statusCode()>=300)return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","智能服务响应较慢，当前显示默认模型");JsonNode data=mapper.readTree(response.body()).path("data");List<String> models=new ArrayList<>();if(data.isArray())data.forEach(x->{String id=x.path("id").asText("");if(!id.isBlank())models.add(id);});if(models.isEmpty())models.add("deepseek-v4-flash");return Map.of("source","LIVE","models",models,"notice","已读取可用模型");}catch(Exception ignored){return Map.of("source","DEMO","models",List.of("deepseek-v4-flash"),"notice","智能服务响应较慢，当前显示默认模型");}}
    Map<String,Object> demoAi(AiAgent agent,String message,String model,String notice){String scenario=agent==null||agent.scenario==null?"工业物联网":agent.scenario;String reply="【"+scenario+"】本地演示建议：先确认设备在线状态与最近遥测趋势，再核对告警等级、规则阈值和现场处置记录；如问题持续，建议安排巡检并保留处理结论。";if(message!=null&&message.contains("巡检"))reply="【巡检计划】本地演示建议：按设备重要度分组，优先检查离线设备、高频告警设备和关键网关，记录温度、湿度、压力及现场照片，完成后复核未关闭告警。";else if(message!=null&&message.contains("告警"))reply="【告警解释】本地演示建议：结合触发规则、遥测峰值和设备位置判断影响范围，先降载或停机保护，再通知值班人员确认传感器与工况是否异常。";else if(message!=null&&(message.contains("状态")||message.contains("分析")))reply="【设备状态分析】本地演示建议：关注在线率、最近上报时间、告警数量和任务执行结果；若设备长时间无上报，优先检查供电、网络与边缘网关连接。";return Map.of("reply",reply,"source","DEMO","model",model==null?"deepseek-v4-flash":model,"notice",notice);} String resolveAiKey(Map<String,Object> req){String requestKey=str(req.get("apiKey"));if(!requestKey.isBlank())return requestKey;String key=Optional.ofNullable(aiApiKey).orElse("").trim();if(!key.isBlank()||!aiAllowLocalKeyFile)return key;try{Path cwd=Path.of("").toAbsolutePath();String fileName="接口文档和API-KEY.txt";List<Path> candidates=new ArrayList<>();if(cwd.getParent()!=null)candidates.add(cwd.getParent().resolve(fileName));if(cwd.getParent()!=null&&cwd.getParent().getParent()!=null)candidates.add(cwd.getParent().getParent().resolve(fileName));Pattern p=Pattern.compile("API-KEY\\s*[:：]\\s*([^\\s]+)");for(Path path:candidates)if(Files.isRegularFile(path)){Matcher m=p.matcher(Files.readString(path,StandardCharsets.UTF_8));if(m.find())return m.group(1).trim();}}catch(Exception ignored){}return "";}
    Double metricValue(String metric,Map<String,Object> req,TelemetryData data){return switch(Optional.ofNullable(metric).orElse("")){case "humidity"->data.humidity;case "pressure"->data.pressure;case "temperature"->data.temperature;default->num(req.get(metric));};}
    static String str(Object o){return o==null?"":String.valueOf(o).trim();} static Double num(Object o){return o==null?null:Double.valueOf(String.valueOf(o));} static boolean compare(double v,String op,double th){return switch(op){case ">="->v>=th;case "<"->v<th;case "<="->v<=th;case "=="->v==th;default->v>th;};} static List<Map<String,Object>> trend(List<LocalDate> days,Map<LocalDate,Long> counts){return days.stream().map(d->Map.<String,Object>of("name",String.format("%02d-%02d",d.getMonthValue(),d.getDayOfMonth()),"value",counts.getOrDefault(d,0L))).toList();}
}
